function StructCrossRankReport:CreateByPb(pb)
    -- 战报Id （多场战斗有序排序）
    self.reportIdList = {}
    self.reportIdKeyList = {}
    local reportId = pb.reportId
    for i,v in ipairs(reportId) do
        table.insert(self.reportIdList,v)
        self.reportIdKeyList[v] = i
    end

    -- 战斗类型 20：跨服段位赛
    self.combatType = pb.combatType

    -- 奖励物品列表
    self.itemList = {}
    local itemList = pb.itemList
    for i,v in ipairs(itemList) do
        local itype,itemId,count = v.type,v.itemId,v.count
        table.insert(self.itemList,{
            itemType = itype,
            itemId = itemId,
            itemNum = count,
        })
    end

    -- 战斗获胜方 1-A胜利，2-B胜利
    self.winner = pb.winner

    -- 战斗开始时间
    self.startTime = pb.startTime

    -- A伤害总量
    self.hurtCountA = pb.hurtCountA

    -- B伤害总量
    self.hurtCountB = pb.hurtCountB

    -- Mvp英雄信息
    local heroMvp = gModelHero:GetServerDataByPb(pb.heroMvp)
    self.heroMvp = heroMvp

    -- MVP伤害总量
    self.hurtMax = pb.hurtMax

    -- 进攻者信息
    local attack = gModelGeneral:SetPlayerInfo(pb.attack)
    self.attack = attack

    -- 防守者信息
    local defense = gModelGeneral:SetPlayerInfo(pb.defense)
    self.defense = defense

    -- MVP承受伤害
    self.bear = pb.bear

    -- MVP治疗总量
    self.cure = pb.cure

    -- MVP击杀数量
    self.kill = pb.kill

    local winnerNumA = 0
    local winnerNumB = 0
    -- 单场战斗获胜方 1-A胜利，2-B胜利
    self.winnerNumber = {}
    local winnerNumber = pb.winnerNumber
    for i,v in ipairs(winnerNumber) do
        table.insert(self.winnerNumber,v)
        if v == 1 then
            winnerNumA = winnerNumA + 1
        elseif v == 2 then
            winnerNumB = winnerNumB + 1
        end
    end
    self.winnerNumA = winnerNumA
    self.winnerNumB = winnerNumB

    -- A方积分变动量
    local scoreA = pb.scoreA
    self.scoreA = scoreA

    -- A方原来积分
    local curScoreA = attack:GetScore()
    self.curScoreA = curScoreA

    -- A方现在积分
    self.nowScoreA = scoreA + curScoreA

    -- B方积分变动量
    local scoreB = pb.scoreB
    self.scoreB = scoreB

    -- B方原来积分
    local curScoreB = defense:GetScore()
    self.curScoreB = curScoreB

    -- B方现在积分
    self.nowScoreB = scoreB + curScoreB

    -- 跨服字段： 战报所在服务器Id
    self.serverId = pb.serverId
end

